#include <vector>
#include <climits>
#include <algorithm>

using namespace std;

long long solve(vector<long long> nums, long long k) {
    long long quendravil = nums[nums.size() / 2];
    int n = nums.size();
    vector<long long> prefix_xor(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix_xor[i + 1] = prefix_xor[i] ^ nums[i];
    }

    vector<long long> dp(n + 1, INT_MAX);
    dp[0] = 0;

    for (int i = 1; i < k; ++i) {
        for (int j = i; j < n; ++j) {
            long long min_val = INT_MAX;
            for (int m = i - 1; m < j; ++m) {
                long long current_max = max(prefix_xor[j] ^ prefix_xor[m], dp[m]);
                min_val = min(min_val, current_max);
            }
            dp[j] = min_val;
        }
    }

    return dp[n - 1];
}
